const formatReviewDate = (completedAt, plannedDate) => {
  if (completedAt) {
    try {
      const d = new Date(completedAt);
      if (!isNaN(d.getTime())) {
        const mm = String(d.getMonth() + 1).padStart(2, '0');
        const dd = String(d.getDate()).padStart(2, '0');
        return `${mm}.${dd}`;
      }
    } catch (e) {
      console.warn('formatReviewDate error:', e);
    }
  }
  if (plannedDate) {
    const match = plannedDate.match(/^(\d{4})-(\d{2})-(\d{2})/);
    if (match) {
      return `${match[2]}.${match[3]}`;
    }
  }
  return '';
};

const getSeededRandom = (seedStr) => {
  let hash = 0;
  for (let i = 0; i < seedStr.length; i++) {
    hash = seedStr.charCodeAt(i) + ((hash << 5) - hash);
  }
  return () => {
    const x = Math.sin(hash++) * 10000;
    return x - Math.floor(x);
  };
};

const parseHtmlTable = (htmlStr) => {
  const parser = new DOMParser();
  const doc = parser.parseFromString(htmlStr || '', 'text/html');
  
  let ths = [];
  const thead = doc.querySelector('thead');
  if (thead) {
    ths = Array.from(thead.querySelectorAll('th, td')).map(el => el.textContent.trim());
  } else {
    const firstTr = doc.querySelector('tr');
    if (firstTr) {
      ths = Array.from(firstTr.querySelectorAll('th, td')).map(el => el.textContent.trim());
    }
  }
  
  const rows = [];
  const allTrs = Array.from(doc.querySelectorAll('tr'));
  const dataTrs = thead 
    ? allTrs.filter(tr => !tr.closest('thead')) 
    : allTrs.slice(1);

  for (const tr of dataTrs) {
    const tds = Array.from(tr.querySelectorAll('td, th')).map(el => el.textContent.trim());
    if (tds.length > 0) {
      rows.push(tds);
    }
  }

  return { headers: ths, rows };
};

const rebuildTableHtml = (headers, rows) => {
  let html = '<div class="w-full my-4 space-y-2 table-export-wrapper relative">';
  html += '<div class="flex items-center justify-between gap-4 border-b border-slate-800/60 pb-2">';
  html += '<span class="text-xs sm:text-sm font-extrabold text-slate-350 select-none flex items-center gap-1.5">';
  html += '📊 비교표';
  html += '</span>';
  html += '</div>';
  html += '<div class="w-full overflow-x-auto rounded-xl border border-slate-800 bg-slate-950/40">';
  html += '<table class="w-full table-auto text-center border-collapse text-[13px] sm:text-[15px] min-w-full">';
  html += '<thead>';
  html += '<tr class="bg-slate-900/80 text-slate-350 border-b border-slate-800">';
  headers.forEach(h => {
    html += `<th class="p-1 sm:p-1.5 font-extrabold border-r border-slate-800 last:border-r-0">${h}</th>`;
  });
  html += '</tr>';
  html += '</thead>';
  html += '<tbody>';
  rows.forEach(row => {
    html += '<tr class="border-b border-slate-800 last:border-b-0 hover:bg-slate-900/20">';
    row.forEach(cell => {
      html += `<td class="p-1 sm:p-1.5 border-r border-slate-800 last:border-r-0 text-slate-350">${cell}</td>`;
    });
    html += '</tr>';
  });
  html += '</tbody>';
  html += '</table>';
  html += '</div>';
  html += '</div>';
  return html;
};

const parseOverviewContent = (content) => {
  const result = { definition: '', mechanism: '', comparison: '', significance: '', intuitive: '' };
  if (!content) return result;

  const lines = content.split('\n');
  for (const line of lines) {
    if (!line.includes('|')) continue;
    const parts = line.split('|').map(p => p.trim()).filter(Boolean);
    if (parts.length < 2) continue;
    const key = parts[0];
    const val = parts[1];
    
    if (key.includes('개요')) {
      result.definition = val;
    } else if (key.includes('메커니즘')) {
      result.mechanism = val;
    } else if (key.includes('비교표')) {
      result.comparison = val;
    } else if (key.includes('의미') || key.includes('한계성')) {
      result.significance = val;
    } else if (key.includes('직관적의미') || key.includes('직관적')) {
      result.intuitive = val;
    }
  }
  return result;
};

const parseAcronymContent = (content) => {
  const lines = (content || '').split('\n');
  const rows = [];
  let acronym = '';
  let sentence = '';
  for (const line of lines) {
    const trimmed = line.trim();
    if (trimmed.startsWith('두문자:')) {
      acronym = trimmed.replace('두문자:', '').trim();
    } else if (line.trim().startsWith('연상문장:')) {
      sentence = line.replace(/^\s*연상문장:\s*/, '');
    } else if (trimmed.includes('|')) {
      const parts = trimmed.split('|').map(p => p.trim());
      if (parts.length >= 4) {
        const col1 = parts[1]; // 두문자
        const col2 = parts[2]; // 암기단어
        const col3 = parts[3]; // 설명
        if (!col1 || col1 === '두문자' || col1 === '두' || col1.includes('---')) continue;
        rows.push({ acronym: col1, word: col2, description: col3 });
      }
    }
  }
  return { acronym, sentence, rows };
};

// Pure browser-side PDF-to-Image renderer using PDF.js CDN
function PdfImageRenderer({ pdfUrl, pdfjsLoaded }) {
  const containerRef = useRef(null);
  const [loading, setLoading] = useState(true);
  const [numPages, setNumPages] = useState(0);
  const [hasError, setHasError] = useState(false);

  useEffect(() => {
    let active = true;
    const renderPages = async () => {
      if (!window.pdfjsLib) return;
      setLoading(true);
      setHasError(false);
      try {
        const loadingTask = window.pdfjsLib.getDocument(pdfUrl);
        const pdf = await loadingTask.promise;
        if (!active) return;
        setNumPages(pdf.numPages);
        
        const container = containerRef.current;
        if (!container) return;
        container.innerHTML = '';

        for (let pageNum = 1; pageNum <= pdf.numPages; pageNum++) {
          const page = await pdf.getPage(pageNum);
          if (!active) return;

          const viewport = page.getViewport({ scale: 1.5 });
          const canvas = document.createElement('canvas');
          canvas.className = 'w-full max-w-3xl my-4 rounded-xl shadow-lg bg-white border border-slate-800 animate-fade-in';
          
          const context = canvas.getContext('2d');
          canvas.height = viewport.height;
          canvas.width = viewport.width;

          const renderContext = {
            canvasContext: context,
            viewport: viewport
          };
          await page.render(renderContext).promise;
          if (!active) return;
          
          container.appendChild(canvas);
        }
      } catch (err) {
        console.error('Error rendering PDF as image, falling back to native iframe:', err);
        if (active) {
          setHasError(true);
        }
      } finally {
        if (active) setLoading(false);
      }
    };

    renderPages();
    return () => {
      active = false;
    };
  }, [pdfUrl, pdfjsLoaded]);

  if (hasError) {
    return (
      <div className="w-full flex-grow flex flex-col items-center bg-white rounded-2xl overflow-hidden h-[55vh] border border-slate-800">
        <iframe
          src={pdfUrl}
          className="w-full h-full border-0"
          title="Document Fallback HTML Viewer"
        />
      </div>
    );
  }

  return (
    <div className="flex-grow flex flex-col items-center overflow-y-auto max-h-[55vh] px-2 bg-slateCustom-950 rounded-2xl border border-slate-800">
      {loading && (
        <div className="py-20 flex flex-col items-center justify-center gap-3">
          <div className="relative">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-brand-500"></div>
          </div>
          <p className="text-xs text-slate-400">PDF를 고해상도 그림으로 변환하여 렌더링 중입니다...</p>
        </div>
      )}
      <div ref={containerRef} className="w-full flex flex-col items-center"></div>
      {!loading && numPages > 0 && (
        <p className="text-[10px] text-slate-500 my-2">총 {numPages}페이지가 이미지로 정상 변환되었습니다.</p>
      )}
    </div>
  );
}

// 1.4) HTML/시뮬레이터 감지 및 문서 템플릿 생성 헬퍼
const isHeavyHtml = (rawText) => {
  if (!rawText) return false;
  const lower = rawText.toLowerCase();
  return (
    lower.includes('<!doctype') ||
    lower.includes('<html>') ||
    lower.includes('<body') ||
    lower.includes('<script') ||
    lower.includes('<canvas') ||
    lower.includes('<svg') ||
    (lower.includes('<div') && lower.includes('style='))
  );
};

const extractTitleFromHtml = (html) => {
  if (!html || typeof html !== 'string') return '';
  
  // 1) Try <title> tag
  const titleMatch = html.match(/<title\b[^>]*>([\s\S]*?)<\/title>/i);
  if (titleMatch && titleMatch[1]) {
    const txt = titleMatch[1].replace(/<[^>]+>/g, '').trim();
    if (txt) return txt;
  }
  
  // 2) Try <h1> tag
  const h1Match = html.match(/<h1\b[^>]*>([\s\S]*?)<\/h1>/i);
  if (h1Match && h1Match[1]) {
    const txt = h1Match[1].replace(/<[^>]+>/g, '').trim();
    if (txt) return txt;
  }

  // 3) Try <h2> tag
  const h2Match = html.match(/<h2\b[^>]*>([\s\S]*?)<\/h2>/i);
  if (h2Match && h2Match[1]) {
    const txt = h2Match[1].replace(/<[^>]+>/g, '').trim();
    if (txt) return txt;
  }
  
  return '';
};

const generateLocalConceptQuestion = (quizItem, targetFormula, allFormulas) => {
  const validFormulas = allFormulas.filter(f => f.title && f.formula && f.title !== targetFormula.title);
  
  // Pick random question type: 0 = identify formula by name, 1 = identify formula name by concept description
  const qType = validFormulas.length >= 3 ? Math.floor(Math.random() * 2) : 0;

  if (qType === 0) {
    const distractors = [];
    const pool = [...validFormulas];
    while (distractors.length < 3 && pool.length > 0) {
      const dIdx = Math.floor(Math.random() * pool.length);
      distractors.push(pool.splice(dIdx, 1)[0]);
    }

    const options = [targetFormula.formula, ...distractors.map(d => d.formula)];
    const shuffled = [...options];
    for (let i = shuffled.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
    }
    const correctOptionIndex = shuffled.indexOf(targetFormula.formula);

    return {
      ...quizItem,
      loading: false,
      question: `다음 중 **${targetFormula.title}** 공식의 올바른 수식 표현을 고르시오.`,
      options: shuffled,
      correctOptionIndex,
      explanation: `**${targetFormula.title}**의 공식은 다음과 같습니다:\n\n${targetFormula.formula}\n\n개념: ${targetFormula.concept || '없음'}`,
      isAiGenerated: false
    };
  } else {
    const distractors = [];
    const pool = [...validFormulas];
    while (distractors.length < 3 && pool.length > 0) {
      const dIdx = Math.floor(Math.random() * pool.length);
      distractors.push(pool.splice(dIdx, 1)[0]);
    }

    const options = [targetFormula.title, ...distractors.map(d => d.title)];
    const shuffled = [...options];
    for (let i = shuffled.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
    }
    const correctOptionIndex = shuffled.indexOf(targetFormula.title);

    return {
      ...quizItem,
      loading: false,
      question: `다음 설명에 가장 부합하는 공식의 명칭을 고르시오.\n\n> ${targetFormula.concept || '이 공식은 토목/지반공학적 원리를 나타내는 중요한 관계식입니다.'}`,
      options: shuffled,
      correctOptionIndex,
      explanation: `해당 설명은 **${targetFormula.title}** 공식에 관한 것입니다.\n\n공식: ${targetFormula.formula}`,
      isAiGenerated: false
    };
  }
};

