  const [realTimeAttachedImage, setRealTimeAttachedImage] = useState(null);
  
  const [realTimeTutorSize, setRealTimeTutorSize] = useState(() => {
    try {
      const saved = localStorage.getItem('anti_realtime_tutor_size');
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed.width && parsed.height) return parsed;
      }
    } catch (e) {}
    const defaultWidth = Math.min(window.innerWidth - 32, 450);
    const defaultHeight = Math.min(window.innerHeight - 32, 600);
    return { width: defaultWidth, height: defaultHeight };
  });

  const [realTimeTutorPos, setRealTimeTutorPos] = useState(() => {
    try {
      const saved = localStorage.getItem('anti_realtime_tutor_pos');
      if (saved) {
        const parsed = JSON.parse(saved);
        if (typeof parsed.x === 'number' && typeof parsed.y === 'number') return parsed;
      }
    } catch (e) {}
    const w = Math.min(window.innerWidth - 32, 450);
    const h = Math.min(window.innerHeight - 32, 600);
    return { x: (window.innerWidth - w) / 2, y: (window.innerHeight - h) / 2 };
  });

  const latestRealTimeTutorSizeRef = useRef({ width: 450, height: 600 });
  const latestRealTimeTutorPosRef = useRef({ x: 0, y: 0 });

  useEffect(() => {
    document.documentElement.style.setProperty('--realtime-tutor-w', `${realTimeTutorSize.width}px`);
    document.documentElement.style.setProperty('--realtime-tutor-h', `${realTimeTutorSize.height}px`);
    latestRealTimeTutorSizeRef.current = realTimeTutorSize;
  }, [realTimeTutorSize]);

  useEffect(() => {
    document.documentElement.style.setProperty('--realtime-tutor-x', `${realTimeTutorPos.x}px`);
    document.documentElement.style.setProperty('--realtime-tutor-y', `${realTimeTutorPos.y}px`);
    latestRealTimeTutorPosRef.current = realTimeTutorPos;
  }, [realTimeTutorPos]);

  const realTimeFileInputRef = useRef(null);
  const realTimeChatBodyRef = useRef(null);

  useEffect(() => {
    localStorage.setItem('anti_realtime_tutor_open', isRealTimeTutorOpen ? 'true' : 'false');
  }, [isRealTimeTutorOpen]);

  useEffect(() => {
    localStorage.setItem('anti_realtime_chat_history', JSON.stringify(realTimeChatHistory));
  }, [realTimeChatHistory]);

  useEffect(() => {
    if (realTimeChatBodyRef.current) {
      realTimeChatBodyRef.current.scrollTop = realTimeChatBodyRef.current.scrollHeight;
    }
  }, [realTimeChatHistory, isRealTimeChatLoading]);

  // AI History Tracking States
  const [aiHistory, setAiHistory] = useState(() => {
    try {
      const saved = localStorage.getItem('anti_ai_history');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });
  const [showAiHistoryModal, setShowAiHistoryModal] = useState(false);
  const [showMemoryTypeSelectPopup, setShowMemoryTypeSelectPopup] = useState(false);
  const [showMainMemoryTypePopup, setShowMainMemoryTypePopup] = useState(false);
  const [showMobileReviewMemoryPopup, setShowMobileReviewMemoryPopup] = useState(false);
  const [showMobileNavbarMemoryPopup, setShowMobileNavbarMemoryPopup] = useState(false);
  const activeProgressIdRef = useRef(null);

  const startProgressPolling = (progressId) => {
    if (progressIntervalRef.current) {
      clearInterval(progressIntervalRef.current);
    }
    setAiProgressMessage('준비 중...');
    setAiProgressPercent(0);
    setShowAiProgress(true);

    activeProgressIdRef.current = progressId;

    // Determine the task name from the ID prefix
    const taskName = (() => {
      if (progressId.startsWith('grade_')) return '주관식 표 채우기 채점';
      if (progressId.startsWith('gen_')) return 'AI 복습 문제 생성';
      if (progressId.startsWith('ref_')) return 'AI 복습 문제 리프레쉬';
      if (progressId.startsWith('exp_')) return 'AI 보기 상세해설 생성';
      if (progressId.startsWith('hint_')) return 'AI 풀이 힌트 생성';
      if (progressId.startsWith('tutor_')) return 'AI 튜터 질의응답';
      if (progressId.startsWith('guide_')) return 'AI 맞춤형 학습 가이드 생성';
      if (progressId.startsWith('exam_gen_')) return 'AI 종합평가 문제 생성';
      if (progressId.startsWith('exam_ref_')) return 'AI 종합평가 문제 리프레쉬';
      if (progressId.startsWith('recreate_')) return 'AI 개별 문항 재출제';
      return 'AI 분석 작업';
    })();

    const newRecord = {
      id: progressId,
      taskName,
      topicTitle: selectedTopic ? selectedTopic.title : '지반공학 종합평가',
      startTime: new Date().toISOString(),
      endTime: null,
      status: 'running',
      modelName: 'gemini-3.5-flash', // Default model
      percent: 0,
      timeline: ['준비 중...'],
      validationLogs: []
    };

    setAiHistory(prev => {
      const updated = [newRecord, ...prev].slice(0, 50);
      localStorage.setItem('anti_ai_history', JSON.stringify(updated));
      return updated;
    });

    progressIntervalRef.current = setInterval(async () => {
      try {
        const res = await fetch(`${API_BASE}/api/progress/${progressId}`);
        if (res.ok) {
          const data = await res.json();
          if (data && data.message) {
            setAiProgressMessage(data.message);
            setAiProgressPercent(data.percentage || 0);

            // Update history progress & timeline
            setAiHistory(prev => {
              const updated = prev.map(item => {
                if (item.id === progressId) {
                  const timeline = Array.isArray(item.timeline) ? [...item.timeline] : [];
                  if (timeline.length === 0 || timeline[timeline.length - 1] !== data.message) {
                    timeline.push(data.message);
                  }

                  // Infer engine model name from message text
                  let modelName = item.modelName;
                  const match = data.message.match(/([a-zA-Z0-9.-]+\s*엔진|[a-zA-Z0-9.-]+\s*Model|GEMINI-[a-zA-Z0-9.-]+|GROK-[a-zA-Z0-9.-]+|GPT-[a-zA-Z0-9.-]+)/i);
                  if (match) {
                    modelName = match[1].replace(/\s*엔진/i, '').trim().toLowerCase();
                  } else if (data.message.toLowerCase().includes('gemini-3.5-flash')) {
                    modelName = 'gemini-3.5-flash';
                  } else if (data.message.toLowerCase().includes('gemini-3.1-flash-lite')) {
                    modelName = 'gemini-3.1-flash-lite';
                  } else if (data.message.toLowerCase().includes('gemini-2.5-flash')) {
                    modelName = 'gemini-2.5-flash';
                  }

                  return {
                    ...item,
                    percent: data.percentage || 0,
                    timeline,
                    modelName
                  };
                }
                return item;
              });
              localStorage.setItem('anti_ai_history', JSON.stringify(updated));
              return updated;
            });
          }
        }
      } catch (err) {
        console.warn('Error polling progress:', err);
      }
    }, 600);
  };

  const stopProgressPolling = (finalMessage = null, finalPercent = 100, isSuccess = true, data = null) => {
    if (progressIntervalRef.current) {
      clearInterval(progressIntervalRef.current);
      progressIntervalRef.current = null;
    }
    if (finalMessage) {
      setAiProgressMessage(finalMessage);
      setAiProgressPercent(finalPercent);
      setTimeout(() => {
        setShowAiProgress(false);
      }, 1500);
    } else {
      setShowAiProgress(false);
    }

    const finishedId = activeProgressIdRef.current;
    if (finishedId) {
      setAiHistory(prev => {
        const updated = prev.map(item => {
          if (item.id === finishedId) {
            const timeline = Array.isArray(item.timeline) ? [...item.timeline] : [];
            
            // Extract model name from questions data or fall back
            let modelName = item.modelName;
            if (data) {
              if (data.modelName) {
                modelName = data.modelName;
              } else if (data.questions && data.questions.some(q => q.modelName)) {
                modelName = data.questions.find(q => q.modelName).modelName;
              } else if (data.question && data.question.modelName) {
                modelName = data.question.modelName;
              }
            }
            if (!modelName) modelName = 'gemini-3.5-flash';

            // Insert detailed timeline logs based on the scenario and actual data returned
            if (data) {
              if (data.isCached) {
                timeline.push(`[캐시 복원] 이전 세션의 문제 세트(${data.questions ? data.questions.length : 0}문항)와 사용자 상태를 즉시 복원했습니다. (API 호출 건너뜀)`);
                timeline.push(`[완료] 데이터 로드가 성공적으로 완료되었습니다.`);
              } else if (data.isFallback) {
                timeline.push(`[로컬 대체] 로컬 백업 문항 데이터베이스에서 예상 문제를 대체 출제했습니다. (API 사용 불가)`);
                timeline.push(`[완료] 로컬 출제 처리가 정상 종료되었습니다.`);
              } else {
                // Real AI call
                const count = data.questions ? data.questions.length : (data.question ? 1 : 0);
                
                // Detailed generation log
                timeline.push(`[1단계: 문제 생성 완료] API 모델 (${modelName})을 사용하여 신규 문항 ${count}개를 성공적으로 생성했습니다.`);
                
                // Detailed validation log
                let repairCount = 0;
                if (Array.isArray(data.questions)) {
                  data.questions.forEach(q => {
                    if (q.validationLogs && q.validationLogs.some(log => log.includes('보정') || log.includes('재작성') || log.includes('교정') || log.includes('오류') || log.includes('이탈'))) {
                      repairCount++;
                    }
                  });
                }
                
                if (repairCount > 0) {
                  timeline.push(`[2단계: 자가 검증 완료] validationPlugin을 활성화하여 공학적 정합성 및 LaTeX 수식 검증을 완료했습니다. (총 ${repairCount}개 문항 결함 보정 및 교정 완료)`);
                } else {
                  timeline.push(`[2단계: 자가 검증 완료] validationPlugin을 활성화하여 공학적 정합성 및 LaTeX 수식 검증을 완료했습니다. (이상 없음, 통과)`);
                }
              }
            } else {
              // Custom details for other tools like grading, explanation, chat etc.
              const isGrading = finishedId.startsWith('grade_');
              const isExplanation = finishedId.startsWith('exp_');
              const isHint = finishedId.startsWith('hint_');
              const isTutor = finishedId.startsWith('tutor_');
              const isGuide = finishedId.startsWith('guide_');
              
              if (isGrading) {
                timeline.push(`[1단계: 제출 답안 분석] 사용자의 주관식 입력 데이터를 AI가 정밀 파싱했습니다.`);
                timeline.push(`[2단계: 채점 및 첨삭 완료] 모델(${modelName})을 사용하여 모범 답안 매칭 및 지반공학 기술사 관점 피드백을 생성했습니다.`);
              } else if (isExplanation) {
                timeline.push(`[1단계: 오답 오답지 분석] 선택지별 개념 구조를 분석했습니다.`);
                timeline.push(`[2단계: 상세 해설 완료] 모델(${modelName})을 사용하여 오답 원인 분석 해설서 작성을 완료했습니다.`);
              } else if (isHint) {
                timeline.push(`[1단계: 문제 힌트 추출] 문제에 적용된 개념적 공식을 도출했습니다.`);
                timeline.push(`[2단계: 힌트 생성 완료] 모델(${modelName})을 사용하여 단계별 접근 방법 및 힌트 생성을 완료했습니다.`);
              } else if (isTutor) {
                timeline.push(`[1단계: 질의 이해] 사용자의 질문 의도 및 전공 개념을 파악했습니다.`);
                timeline.push(`[2단계: 답변 피드백 완료] 모델(${modelName})을 사용하여 튜터링 답변 렌더링을 마쳤습니다.`);
              } else if (isGuide) {
                timeline.push(`[1단계: 취약 영역 진단] 오답 통계를 분석했습니다.`);
                timeline.push(`[2단계: 가이드 작성 완료] 모델(${modelName})을 사용하여 맞춤형 로드맵 가이드 작성을 완료했습니다.`);
              } else {
                const displayMsg = finalMessage || (isSuccess ? '작업이 성공적으로 종료되었습니다.' : '작업 수행 실패');
                if (timeline[timeline.length - 1] !== displayMsg) {
                  timeline.push(displayMsg);
                }
              }
            }

            // Extract validation/healing logs from questions data
            let validationLogs = [];
            if (data) {
              if (Array.isArray(data.questions)) {
                let checkCount = 0;
                data.questions.forEach((q, idx) => {
                  if (Array.isArray(q.validationLogs)) {
                    q.validationLogs.forEach(log => {
                      if (log.includes('보정') || log.includes('재작성') || log.includes('교정') || log.includes('오류') || log.includes('이탈')) {
                        validationLogs.push(`[${idx + 1}번 문제] ${log}`);
                      } else {
                        checkCount++;
                      }
                    });
                  }
                });
                if (validationLogs.length === 0 && checkCount > 0) {
                  validationLogs.push(`[전체 검수 완료] 총 ${data.questions.length}개 문항에 대해 공학적 정합성, LaTeX 수식 및 표 레이아웃 자가 검증을 진행하였으며, 발견된 결함이 없어 원본 규격 그대로 통과했습니다.`);
                }
              } else if (data.question && Array.isArray(data.question.validationLogs)) {
                data.question.validationLogs.forEach(log => {
                  validationLogs.push(`[문제] ${log}`);
                });
              }
            }

            return {
              ...item,
              endTime: new Date().toISOString(),
              status: isSuccess ? 'success' : 'failed',
              percent: finalPercent,
              timeline,
              modelName,
              validationLogs: validationLogs.length > 0 ? validationLogs : item.validationLogs
            };
          }
          return item;
        });
        localStorage.setItem('anti_ai_history', JSON.stringify(updated));
        return updated;
      });
      activeProgressIdRef.current = null;
    }
  };
  const [revealedQuestions, setRevealedQuestions] = useState({}); // Stores which question answers are unblurred/revealed
  const [selectedAnswers, setSelectedAnswers] = useState({}); // Stores chosen options for multiple choice questions { [questionIdx]: optionString }
  const [tableAnswers, setTableAnswers] = useState({}); // Stores user text inputs for table fill-in questions
  const [tableGradingResults, setTableGradingResults] = useState({});
  const [examTableAnswers, setExamTableAnswers] = useState({});
  const [examTableGradingResults, setExamTableGradingResults] = useState({});
  const [showAnswersState, setShowAnswersState] = useState({});
  const [examShowAnswersState, setExamShowAnswersState] = useState({});
  const [gradingLoading, setGradingLoading] = useState({});

  const gradeTableQuestion = async (qIdx, q) => {
    setGradingLoading(prev => ({ ...prev, [qIdx]: true }));
    const inputs = Object.keys(q.answers || {});
    const activeAnswers = showExam ? examTableAnswers : tableAnswers;
    const activeSetGradingResults = showExam ? setExamTableGradingResults : setTableGradingResults;
    
    const currentGrading = showExam ? examTableGradingResults : tableGradingResults;
    const nextGrading = { ...currentGrading };
    
    const progressId = 'grade_' + Math.random().toString(36).substring(2, 9);
    startProgressPolling(progressId);

    const promises = inputs.map(async (inputId) => {
      const userAnswer = activeAnswers[`${qIdx}_${inputId}`] || '';
      const correctAnswer = q.answers[inputId] || '';
      
      let rowHeader = '';
      let colHeader = '';
      if (q.tableData && q.tableData.rows && q.tableData.headers) {
        q.tableData.rows.forEach((row) => {
          row.forEach((cell, colIdx) => {
            if (typeof cell === 'string' && cell.includes(`[${inputId}]`)) {
              rowHeader = row[0] || '';
              colHeader = q.tableData.headers[colIdx] || '';
            }
          });
        });
      }
      
      try {
        const res = await fetch(`${API_BASE}/api/grade-subjective`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            question: q.question,
            correctAnswer,
            userAnswer,
            rowHeader,
            colHeader,
            explanation: q.explanation || q.answer || '',
            category: showExam ? examTopic?.category : selectedTopic?.category,
            progressId
          })
        });
        const data = await res.json();
        nextGrading[`${qIdx}_${inputId}`] = {
          isCorrect: data.isCorrect,
          score: data.score,
          reason: data.reason,
          suggestedModelAnswer: data.suggestedModelAnswer
        };
      } catch (err) {
        console.error('Grading error:', err);
        const normalize = (s) => (s || '').trim().toLowerCase().replace(/\s+/g, '');
        const isCorrect = normalize(userAnswer) === normalize(correctAnswer);
        nextGrading[`${qIdx}_${inputId}`] = {
          isCorrect,
          score: isCorrect ? 10 : 0,
          reason: isCorrect ? '단순 일치(로컬 채점)' : '모범 답안과 불일치'
        };
      }
    });

    try {
      await Promise.all(promises);
      
      activeSetGradingResults(nextGrading);

      // Save state immediately to DB/session to guarantee persistence
      if (!showExam && selectedTopic && selectedTopic.id && aiQuestions.length > 0 && !selectedTopic.isReadOnly) {
        await fetch(`${API_BASE}/api/session/review`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            topicId: selectedTopic.id,
            scheduleId: selectedTopic.schedule_id,
            sessionId: reviewSessionId,
            questions: aiQuestions,
            selectedAnswers,
            revealedQuestions,
            tableAnswers,
            tableGradingResults: nextGrading,
            savedQuizScroll: quizBodyRef.current?.scrollTop || 0
          })
        }).catch(e => console.warn('복습 세션 동기화 실패:', e));
      }

      if (showExam && examQuestions.length > 0 && !loadingExam) {
        await fetch(`${API_BASE}/api/session/exam`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            examQuestions,
            examRevealed,
            examAnswers,
            examTopic,
            tableAnswers: examTableAnswers,
            tableGradingResults: nextGrading,
            tutorAnswers,
            tutorInputText,
            chatHistory,
            savedExamScroll: examBodyRef.current?.scrollTop || 0
          })
        }).catch(e => console.warn('종합평가 세션 동기화 실패:', e));
      }

      stopProgressPolling('채점 완료!', 100);
      return nextGrading;
    } catch (e) {
      stopProgressPolling('채점 실패', 100, false);
    } finally {
      setGradingLoading(prev => ({ ...prev, [qIdx]: false }));
    }
  };

  const getReviewTotalScore = () => {
    let total = 0;
    const scoredIndices = [];
    aiQuestions.forEach((_, i) => {
      scoredIndices.push(i);
    });
    const M = scoredIndices.length;
    if (M === 0) return 0;
    const baseWeight = Math.floor(100 / M);
    const remainder = 100 - (baseWeight * M);

    aiQuestions.forEach((q, idx) => {
      const sIdx = scoredIndices.indexOf(idx);
      const W = sIdx !== -1 ? (sIdx < remainder ? (baseWeight + 1) : baseWeight) : 0;
      const isMC = q.type === '객관식' || (q.options && q.options.length > 0);

      if (isMC) {
        const userAnswer = selectedAnswers[idx];
        const isCorrect = userAnswer !== undefined && userAnswer === q.answer;
        if (isCorrect) {
          total += W;
        }
      } else if (q.type === '주관식 (앞글자)') {
        let sumVal = 0;
        let countVal = 0;
        
        const combGrading = tableGradingResults[`${idx}_ACRONYM_COMB`];
        if (combGrading && combGrading.score !== undefined) {
          sumVal += combGrading.score;
        }
        countVal++;
        
        const rowCount = q.tableData?.rows?.length || 0;
        for (let rIdx = 0; rIdx < rowCount; rIdx++) {
          const rowGrading = tableGradingResults[`${idx}_ROW_${rIdx}_COMB`];
          if (rowGrading && rowGrading.score !== undefined) {
            sumVal += rowGrading.score;
          }
          countVal++;
        }
        if (countVal > 0) {
          total += (sumVal / (countVal * 10)) * W;
        }
      } else if (q.tableData) {
        const inputIds = Object.keys(q.answers || {});
        let sumVal = 0;
        let countVal = inputIds.length;
        inputIds.forEach(inputId => {
          const grading = tableGradingResults[`${idx}_${inputId}`];
          if (grading && grading.score !== undefined) {
            sumVal += grading.score;
          }
        });
        if (countVal > 0) {
          total += (sumVal / (countVal * 10)) * W;
        }
      } else {
        const grading = tableGradingResults[`${idx}_INPUT`];
        if (grading && grading.score !== undefined) {
          total += (grading.score / 10) * W;
        }
      }
    });
    return Math.round(total * 10) / 10;
  };

  const getDisplayReviewScore = () => {
    if (!selectedTopic) return 0;
    if (selectedTopic.isReadOnly) {
      const schedId = selectedTopic.schedule_id;
      if (schedId) {
        const todaySched = todayReviews.find(r => r.schedule_id === schedId);
        if (todaySched && todaySched.score !== undefined && todaySched.score !== null) {
          return todaySched.score;
        }
        for (const topic of allTopics) {
          if (topic.schedules) {
            const s = topic.schedules.find(x => x.id === schedId);
            if (s && s.score !== undefined && s.score !== null) {
              return s.score;
            }
          }
        }
      }
    }
    return getReviewTotalScore();
  };

  const getExamTotalScore = () => {
    let total = 0;
    const scoredIndices = [];
    examQuestions.forEach((_, i) => {
      scoredIndices.push(i);
    });
    const M = scoredIndices.length;
    if (M === 0) return 0;
    const baseWeight = Math.floor(100 / M);
    const remainder = 100 - (baseWeight * M);

    examQuestions.forEach((q, idx) => {
      const sIdx = scoredIndices.indexOf(idx);
      const W = sIdx !== -1 ? (sIdx < remainder ? (baseWeight + 1) : baseWeight) : 0;
      const isMC = q.type === '객관식' || (q.options && q.options.length > 0);

      if (isMC) {
        const userAnswer = examAnswers[idx];
        const normalizeAns = (s) => (s || '').replace(/^\d+\.\s*/, '').trim();
        const isCorrect = userAnswer !== undefined && normalizeAns(userAnswer) === normalizeAns(q.answer);
        if (isCorrect) {
          total += W;
        }
      } else if (q.tableData) {
        const inputIds = Object.keys(q.answers || {});
        let sumVal = 0;
        let countVal = inputIds.length;
        inputIds.forEach(inputId => {
          const grading = examTableGradingResults[`${idx}_${inputId}`];
          if (grading && grading.score !== undefined) {
            sumVal += grading.score;
          }
        });
        if (countVal > 0) {
          total += (sumVal / (countVal * 10)) * W;
        }
      } else {
        const grading = examTableGradingResults[`${idx}_INPUT`];
        if (grading && grading.score !== undefined) {
          total += (grading.score / 10) * W;
        }
      }
    });
    return Math.round(total * 10) / 10;
  };

  const gradeSubjectiveQuestion = async (qIdx, q) => {
    setGradingLoading(prev => ({ ...prev, [qIdx]: true }));
    const activeAnswers = showExam ? examTableAnswers : tableAnswers;
    const activeSetGradingResults = showExam ? setExamTableGradingResults : setTableGradingResults;

    const userAnswer = activeAnswers[`${qIdx}_INPUT`] || '';
    const correctAnswer = q.answer || q.concept || '';
    
    const progressId = 'grade_' + Math.random().toString(36).substring(2, 9);
    startProgressPolling(progressId);

    let newResult = null;
    try {
      const res = await fetch(`${API_BASE}/api/grade-subjective`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          question: q.question,
          correctAnswer,
          userAnswer,
          explanation: q.explanation || '',
          category: showExam ? examTopic?.category : selectedTopic?.category,
          progressId
        })
      });
      const data = await res.json();
      newResult = {
        isCorrect: data.isCorrect,
        score: data.score,
        reason: data.reason,
        suggestedModelAnswer: data.suggestedModelAnswer
      };
      stopProgressPolling('채점 완료!', 100);
    } catch (err) {
      console.error('Grading error:', err);
      const normalize = (s) => (s || '').trim().toLowerCase().replace(/\s+/g, '');
      const isCorrect = normalize(userAnswer) === normalize(correctAnswer);
      newResult = {
        isCorrect,
        score: isCorrect ? 10 : 0,
        reason: isCorrect ? '단순 일치(로컬 채점)' : '모범 답안과 불일치'
      };
      stopProgressPolling('채점 실패', 100, false);
    }

    if (newResult) {
      activeSetGradingResults(prev => {
        const nextResults = {
          ...prev,
          [`${qIdx}_INPUT`]: newResult
        };

        // 즉시 DB 저장하여 지속성 보장
        if (!showExam && selectedTopic && selectedTopic.id && aiQuestions.length > 0 && !selectedTopic.isReadOnly) {
          fetch(`${API_BASE}/api/session/review`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              topicId: selectedTopic.id,
              scheduleId: selectedTopic.schedule_id,
              sessionId: reviewSessionId,
              questions: aiQuestions,
              selectedAnswers,
              revealedQuestions,
              tableAnswers,
              tableGradingResults: nextResults,
              tutorAnswers,
              tutorInputText,
              chatHistory,
              savedQuizScroll: quizBodyRef.current?.scrollTop || 0
            })
          })
            .then(res => res.json())
            .then(data => {
              if (data.success) {
                lastSyncStateRef.current = {
                  selectedAnswers,
                  revealedQuestions,
                  tableGradingResults: nextResults,
                  chatHistory
                };
              }
            })
            .catch(e => console.warn('복습 세션 동기화 실패:', e));
        }

        if (showExam && examQuestions.length > 0 && !loadingExam) {
          fetch(`${API_BASE}/api/session/exam`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              examQuestions,
              examRevealed,
              examAnswers,
              examTopic,
              tableAnswers: examTableAnswers,
              tableGradingResults: nextResults,
              savedExamScroll: examBodyRef.current?.scrollTop || 0
            })
          }).catch(e => console.warn('시험 세션 동기화 실패:', e));
        }

        return nextResults;
      });
    }

    setGradingLoading(prev => ({ ...prev, [qIdx]: false }));
    return newResult;
  };

