    // Fetch reviews based on selected reference date
  const fetchTodayReviews = async (dateStr) => {
    setLoadingReviews(true);
    try {
      let tables = formulaTables;
      let acronyms = formulaAcronyms;
      let overviews = formulaOverviews;
      
      if (tables.length === 0 || acronyms.length === 0 || overviews.length === 0) {
        tables = await loadFormulaTables();
        acronyms = await loadFormulaAcronyms();
        overviews = await loadFormulaOverviews();
      }

      const [res, mixedRes] = await Promise.all([
        fetch(`${API_BASE}/api/dashboard?date=${dateStr}`),
        fetch(`${API_BASE}/api/session/mixed-completed?t=${Date.now()}`).catch(e => null)
      ]);
      const data = await res.json();

      let serverCompletedDates = [];
      if (mixedRes && mixedRes.ok) {
        try {
          const mixedBody = await mixedRes.json();
          if (mixedBody && mixedBody.data && Array.isArray(mixedBody.data.completedDates)) {
            serverCompletedDates = mixedBody.data.completedDates;
            if (serverCompletedDates.includes(dateStr)) {
              localStorage.setItem(`anti_mixed_completed_${dateStr}`, 'true');
            } else {
              localStorage.removeItem(`anti_mixed_completed_${dateStr}`);
            }
          }
        } catch (e) {
          console.warn('Failed to parse mixed completed dates from server:', e);
        }
      }

      if (res.ok && data && Array.isArray(data.reviews)) {
        // 동일 토픽 중복 일정 방어 (중복 시 가장 낮은 review_round 일정 하나만 프론트에서도 유지)
        const uniqueMap = new Map();
        for (const r of data.reviews) {
          const existing = uniqueMap.get(r.topic_id);
          if (!existing || r.review_round < existing.review_round) {
            uniqueMap.set(r.topic_id, r);
          }
        }
        const uniqueList = Array.from(uniqueMap.values());
        
        const hasItems = tables.length > 0 || acronyms.length > 0 || overviews.length > 0;
        const isMixedCompleted = localStorage.getItem(`anti_mixed_completed_${dateStr}`) === 'true';
        
        if (hasItems && !isMixedCompleted) {
          const mixedItem = {
            schedule_id: `mixed_schedule_${dateStr}`,
            topic_id: `mixed_${dateStr}`,
            title: '오늘의 필수 믹스복습 (10제 1세트)',
            planned_date: '1970-01-01',
            review_round: 'MIX',
            category: '믹스',
            pdf_name: 'mixed.html',
            isBonus: false
          };
          uniqueList.push(mixedItem);
        }

        uniqueList.sort((a, b) => {
          const isAMixed = typeof a.topic_id === 'string' && a.topic_id.startsWith('mixed_');
          const isBMixed = typeof b.topic_id === 'string' && b.topic_id.startsWith('mixed_');
          if (isAMixed && !isBMixed) return -1;
          if (!isAMixed && isBMixed) return 1;
          
          const dateA = a.planned_date || '';
          const dateB = b.planned_date || '';
          if (dateA !== dateB) return dateA.localeCompare(dateB);
          
          const isAWeakness = a.review_round === 99 || a.isBonus;
          const isBWeakness = b.review_round === 99 || b.isBonus;
          if (isAWeakness && !isBWeakness) return -1;
          if (!isAWeakness && isBWeakness) return 1;
          
          if ((a.review_round || 0) !== (b.review_round || 0)) {
            return (a.review_round || 0) - (b.review_round || 0);
          }
          return (a.topic_id || 0) - (b.topic_id || 0);
        });
        setTodayReviews(uniqueList);
        if (data && Array.isArray(data.completedTopicIds)) {
          setCompletedTopicIds(data.completedTopicIds);
        } else {
          setCompletedTopicIds([]);
        }
      } else {
        setTodayReviews([]);
        setCompletedTopicIds([]);
        console.error('Failed to load dashboard or invalid data format:', data);
      }
    } catch (err) {
      setTodayReviews([]);
      setCompletedTopicIds([]);
      console.error('Error fetching dashboard:', err);
    } finally {
      setLoadingReviews(false);
    }
  };

  // Fetch all question feedbacks
