                                                      const updatedTables = formulaTables.map(item => item.id === t.id ? { ...item, html: newHtml } : item);
                                                      setFormulaTables(updatedTables);
                                                      handleSaveFormulaTables(updatedTables, false);
                                                      showNotification('새 행이 추가되었습니다.', 'success');
